import hashlib
import os


def hash_file(filepath, algorithm='sha256', chunk_size=8192):
    """
    Create a cryptographic hash of a file for integrity checking.
    
    Args:
        filepath: Path to the file to hash.
        algorithm: Hash algorithm to use (default: sha256).
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).
    
    Returns:
        Hex digest string of the file hash.
    
    Raises:
        FileNotFoundError: If the file does not exist.
        ValueError: If the algorithm is not supported.
    """
    supported_algorithms = hashlib.algorithms_available
    if algorithm not in supported_algorithms:
        raise ValueError(
            f"Unsupported algorithm '{algorithm}'. "
            f"Supported: {sorted(supported_algorithms)}"
        )

    hasher = hashlib.new(algorithm)

    with open(filepath, 'rb') as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hasher.update(chunk)

    return hasher.hexdigest()


def hash_file_with_hmac(filepath, key=None, algorithm='sha256', chunk_size=8192):
    """
    Create an HMAC-based hash of a file for integrity checking with authentication.
    
    Uses a secret key to produce a keyed hash, preventing tampering by anyone
    who doesn't possess the key.
    
    Args:
        filepath: Path to the file to hash.
        key: Secret key as bytes. If None, a secure random key is generated
             and returned alongside the digest.
        algorithm: Hash algorithm to use (default: sha256).
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).
    
    Returns:
        A dict with 'digest' (hex string) and 'key' (bytes).
        If a key was provided, 'key' contains that same key.
        If no key was provided, 'key' contains the newly generated key.
    """
    import hmac

    generated_key = key is None
    if generated_key:
        # Generate a cryptographically secure random key
        # Use a key length matching the hash digest size
        digest_size = hashlib.new(algorithm).digest_size
        key = os.urandom(digest_size)

    if isinstance(key, str):
        key = key.encode('utf-8')

    mac = hmac.new(key, digestmod=lambda: hashlib.new(algorithm))

    with open(filepath, 'rb') as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            mac.update(chunk)

    return {
        'digest': mac.hexdigest(),
        'key': key,
        'algorithm': algorithm,
        'key_was_generated': generated_key,
    }


def verify_file(filepath, expected_hash, algorithm='sha256', chunk_size=8192):
    """
    Verify a file's integrity by comparing its hash to an expected value.
    Uses constant-time comparison to prevent timing attacks.
    
    Args:
        filepath: Path to the file to verify.
        expected_hash: The expected hex digest string.
        algorithm: Hash algorithm that was used (default: sha256).
        chunk_size: Size of chunks to read at a time.
    
    Returns:
        True if the file matches the expected hash, False otherwise.
    """
    import hmac as _hmac

    actual_hash = hash_file(filepath, algorithm=algorithm, chunk_size=chunk_size)
    # Use constant-time comparison to prevent timing side-channel attacks
    return _hmac.compare_digest(actual_hash, expected_hash)


def verify_file_hmac(filepath, expected_digest, key, algorithm='sha256', chunk_size=8192):
    """
    Verify a file's integrity and authenticity using HMAC.
    Uses constant-time comparison to prevent timing attacks.
    
    Args:
        filepath: Path to the file to verify.
        expected_digest: The expected HMAC hex digest string.
        key: The secret key (bytes) used to create the original HMAC.
        algorithm: Hash algorithm that was used (default: sha256).
        chunk_size: Size of chunks to read at a time.
    
    Returns:
        True if the file matches the expected HMAC digest, False otherwise.
    """
    import hmac as _hmac

    result = hash_file_with_hmac(filepath, key=key, algorithm=algorithm, chunk_size=chunk_size)
    return _hmac.compare_digest(result['digest'], expected_digest)


